#include <iostream>
#include <fstream>
#include <string>
#include <sys/stat.h>
using namespace std;

bool fileExists(const string& filename) {
    struct stat buffer;
    return (stat(filename.c_str(), &buffer) == 0);
}

int main() {
    string filename = "log.txt";

    // Check if file exists
    if (fileExists(filename)) {
        cout << "File exists. Appending data..." << endl;
    } else {
        cout << "File does not exist. Creating new file..." << endl;
    }

    // Append mode - ios::app adds data at end
    ofstream outFile(filename, ios::app);

    if (!outFile) {
        cerr << "Error: Cannot open file" << endl;
        return 1;
    }

    // Write timestamped log entries
    outFile << "Log Entry 1: Program started" << endl;
    outFile << "Log Entry 2: Processing data" << endl;
    outFile << "Log Entry 3: Operation completed" << endl;
    outFile.close();

    cout << "Log entries appended successfully" << endl;

    // Read and display file contents
    ifstream inFile(filename);
    string content;
    int lineCount = 0;

    while (getline(inFile, content)) {
        lineCount++;
        cout << lineCount << ": " << content << endl;
    }

    cout << "\nTotal lines: " << lineCount << endl;
    inFile.close();

    return 0;
}

#include <iostream>
#include <fstream>
#include <string>
using namespace std;

struct Student {
    int rollNo;
    char name[50];
    float marks;
};

void writeStudent(fstream& file, const Student& s, int position) {
    // Position: 0-based record number
    int offset = position * sizeof(Student);
    file.seekp(offset, ios::beg);
    file.write(reinterpret_cast<const char*>(&s), sizeof(Student));
}

Student readStudent(fstream& file, int position) {
    Student s;
    int offset = position * sizeof(Student);
    file.seekg(offset, ios::beg);
    file.read(reinterpret_cast<char*>(&s), sizeof(Student));
    return s;
}

int main() {
    const string filename = "students.dat";

    // Open file in binary mode for writing
    fstream outFile(filename, ios::binary | ios::out);

    if (!outFile) {
        cerr << "Error: Cannot create file" << endl;
        return 1;
    }

    // Write 3 student records
    Student students[3] = {
        {1, "Amit Kumar", 85.5f},
        {2, "Priya Singh", 92.0f},
        {3, "Rahul Verma", 78.5f}
    };

    for (int i = 0; i < 3; i++) {
        outFile.write(reinterpret_cast<const char*>(&students[i]), sizeof(Student));
    }
    outFile.close();

    cout << "Binary file created with " << sizeof(Student) << " byte records" << endl;

    // Open file for random access reading
    fstream inFile(filename, ios::binary | ios::in | ios::out);

    if (!inFile) {
        cerr << "Error: Cannot open file" << endl;
        return 1;
    }

    // Read specific records using random access
    cout << "\nReading specific records:" << endl;

    Student s1 = readStudent(inFile, 0); // First record
    cout << "Record 0: " << s1.name << " - Roll: " << s1.rollNo << " - Marks: " << s1.marks << endl;

    Student s2 = readStudent(inFile, 2); // Third record
    cout << "Record 2: " << s2.name << " - Roll: " << s2.rollNo << " - Marks: " << s2.marks << endl;

    // Modify a record using random access
    Student updated = {2, "Priya Sharma", 95.5f};
    writeStudent(inFile, updated, 1); // Update second record

    // Verify update
    Student modified = readStudent(inFile, 1);
    cout << "\nAfter update - Record 1: " << modified.name << " - Marks: " << modified.marks << endl;

    inFile.close();

    return 0;
}
